69	void boot_init_thread(void)
70	{
71	    int old_flags;
72	    struct thread *th;
73	
74	    th = slab_alloc(&thread_slab);
75	    th->state = THREAD_RUNNING;
76	    th->proc = kernel_proc;
77	    th->id = __sync_fetch_and_add(&next_thread_id, 1);
78	    strlcpy(th->name, "idle_thread", sizeof(th->name));
79	
