94	struct thread *spawn_thread_internal(const char *name,
95	                                     struct process *proc,
96	                                     void (*init_func)(),
97	                                     thread_start_func_t start_func,
98	                                     void *param,
99	                                     int kernel_only)
100	{
101	    int old_flags;
102	    struct thread *th;
103	
104	    th = slab_alloc(&thread_slab);
105	    strlcpy(th->name, name, sizeof(th->name));
106	    th->kernel_stack_area = create_area(get_kernel_address_space(),
107	                                        0xffffffff, KERNEL_STACK_SIZE,
108	                                        PLACE_SEARCH_DOWN, "kernel stack",
109	                                        AREA_WIRED | AREA_WRITABLE, 0, 0);
110	    th->kernel_stack_ptr = (unsigned int*) (th->kernel_stack_area->high_address + 1);
111	    th->current_stack = (unsigned int*) ((unsigned char*) th->kernel_stack_ptr
112	        - CONTEXT_FRAME_SIZE);
113	    th->proc = proc;
114	
115	    // Location of RA register in context frame. See context_switch.S.
116	    ((unsigned int*) th->current_stack)[0x818 / 4] = (unsigned int) init_func;
117	
118	    th->start_func = start_func;
119	    th->param = param;
120	    th->id = __sync_fetch_and_add(&next_thread_id, 1);
121	    th->state = THREAD_READY;
122	    if (!kernel_only)
123	    {
124	        th->user_stack_area = create_area(proc->space, 0xffffffff, 0x10000,
125	                                          PLACE_SEARCH_DOWN, "user stack",
126	                                          AREA_WRITABLE, 0, 0);
127	    }
128	    else
129	        th->user_stack_area = 0;
130	
131	    old_flags = disable_interrupts();
132	
133	    // Stick in process list
134	    acquire_spinlock(&proc->lock);
135	    list_add_tail(&proc->thread_list, &th->process_entry);
136	    release_spinlock(&proc->lock);
137	
138	    // Put into ready queue
139	    acquire_spinlock(&thread_q_lock);
140	    list_add_tail(&ready_q, th);
141	    release_spinlock(&thread_q_lock);
142	    restore_interrupts(old_flags);
143	
144	    return th;
145	}
