155	static void destroy_thread(struct thread *th)
156	{
157	    struct process *proc = th->proc;
158	    int old_flags;
159	
160	    VM_DEBUG("cleaning up thread %d (%s)\n", th->id, th->name);
161	
162	    assert(th->state == THREAD_DEAD);
163	
164	    old_flags = acquire_spinlock_int(&proc->lock);
165	    list_remove_node(&th->process_entry);
166	    release_spinlock_int(&proc->lock, old_flags);
167	
168	    // A thread cannot clean itself up. The kernel stack would go away and
169	    // crash.
170	    assert(th != current_thread());
171	
172	    if (th->user_stack_area)
173	    {
174	        VM_DEBUG("free user stack\n");
175	        destroy_area(th->proc->space, th->user_stack_area);
176	    }
177	
178	    VM_DEBUG("free kernel stack\n");
179	    destroy_area(th->proc->space, th->kernel_stack_area);
180	    slab_free(&thread_slab, th);
181	    dec_proc_ref(proc);
182	}
183	
184	void dec_proc_ref(struct process *proc)
185	{
186	    int old_flags;
187	
188	    assert(current_thread()->proc != proc);
189	
190	    if (__sync_add_and_fetch(&proc->ref_count, -1) == 0)
191	    {
192	        VM_DEBUG("destroying process %d\n", proc->id);
193	        assert(list_is_empty(&proc->thread_list));
194	
195	        old_flags = acquire_spinlock_int(&process_list_lock);
196	        list_remove_node(proc);
197	        release_spinlock_int(&process_list_lock, old_flags);
198	
199	        destroy_address_space(proc->space);
200	        slab_free(&process_slab, proc);
201	    }
202	}
203	
204	int grim_reaper(void *ignore)
205	{
206	    struct thread *th;
207	    int old_flags;
208	
209	    (void) ignore;
210	
211	    // Pull off dead thread list
212	    // call destroy_thread
213	    for (;;)
214	    {
215	        // Dequeue a thread to kill
216	        old_flags = acquire_spinlock_int(&thread_q_lock);
217	        th = list_remove_head(&dead_q, struct thread);
218	        release_spinlock_int(&thread_q_lock, old_flags);
219	
220	        if (th == 0)
221	        {
222	            reschedule();   // XXX currently no way to wait
223	            continue;
224	        }
225	
226	        VM_DEBUG("grim_reaper harvesting thread %d (%s)\n", th->id, th->name);
227	        destroy_thread(th);
228	        VM_DEBUG("it is done\n");
229	    }
230	}
