237	    // Need to release the lock acquired at the beginning of that function.
238	    release_spinlock(&thread_q_lock);
239	    restore_interrupts(FLAG_INTERRUPT_EN | FLAG_MMU_EN | FLAG_SUPERVISOR_EN);
240	
241	    jump_to_user_mode(0, 0, (unsigned int) th->start_func,
