260	    // Need to release the lock acquired at the beginning of that function.
261	    release_spinlock(&thread_q_lock);
262	    restore_interrupts(FLAG_INTERRUPT_EN | FLAG_MMU_EN | FLAG_SUPERVISOR_EN);
