274	                                 start_func, param, 1);
275	}
276	
277	void reschedule(void)
278	{
279	    int hwthread = current_hw_thread();
280	    struct thread *old_thread;
281	    struct thread *next_thread;
282	    int old_flags;
283	
284	    assert(!disable_preempt_count[hwthread]);
285	
286	    // Put current thread back on ready queue
287	
288	    old_flags = acquire_spinlock_int(&thread_q_lock);
289	    old_thread = cur_thread[hwthread];
290	    assert(old_thread->state != THREAD_READY);
291	
292	    if (old_thread->state == THREAD_RUNNING)
293	    {
294	        old_thread->state = THREAD_READY;
295	        list_add_tail(&ready_q, old_thread);
296	    }
297	
298	    next_thread = list_remove_head(&ready_q, struct thread);
299	    assert(next_thread);
300	    next_thread->state = THREAD_RUNNING;
301	
302	    if (old_thread != next_thread)
303	    {
304	        cur_thread[hwthread] = next_thread;
305	        trap_kernel_stack[hwthread] = (unsigned int) next_thread->kernel_stack_ptr;
306	        switch_to_translation_map(next_thread->proc->space->translation_map);
307	        context_switch(&old_thread->current_stack, next_thread->current_stack);
308	    }
309	
310	    release_spinlock_int(&thread_q_lock, old_flags);
311	}
312	
313	void disable_preempt(void)
314	{
315	    __sync_fetch_and_add(&disable_preempt_count[current_hw_thread()], 1);
316	}
317	
318	void enable_preempt(void)
319	{
320	    __sync_fetch_and_add(&disable_preempt_count[current_hw_thread()], -1);
321	}
322	
323	static void __attribute__((noreturn)) new_process_start(void)
324	{
325	    struct thread *th = current_thread();
326	
327	    // We will branch here from within reschedule, after context_switch.
328	    // Need to release the lock acquired at the beginning of that function.
329	    release_spinlock(&thread_q_lock);
330	    restore_interrupts(FLAG_INTERRUPT_EN | FLAG_MMU_EN | FLAG_SUPERVISOR_EN);
331	
332	    // XXX could pass argument information here.
333	    jump_to_user_mode(0, 0, (unsigned int) th->start_func,
334	                      th->user_stack_area->high_address + 1);
335	}
