337	struct process *exec_program(const char *filename)
338	{
339	    struct process *proc;
340	    unsigned int entry_point;
341	    int old_flags;
342	
343	    proc = slab_alloc(&process_slab);
344	    proc->id = __sync_fetch_and_add(&next_process_id, 1);
345	    proc->space = create_address_space();
346	    proc->lock = 0;
347	    proc->ref_count = 2; // one ref for thread, one for returned pointer
348	    list_init(&proc->thread_list);
349	
350	    old_flags = disable_interrupts();
351	    acquire_spinlock(&process_list_lock);
352	    list_add_tail(&process_list, proc);
353	    release_spinlock(&process_list_lock);
354	    restore_interrupts(old_flags);
355	
356	    if (load_program(proc, filename, &entry_point) < 0)
357	    {
358	        // XXX cleanup
359	        kprintf("load_program failed\n");
360	        return 0;
361	    }
362	
363	    spawn_thread_internal("user_thread", proc, new_process_start,
364	        (thread_start_func_t) entry_point, 0, 0);
365	    return proc;
366	}
367	
368	void thread_exit(int retcode)
369	{
370	    struct thread *th = current_thread();
371	    (void) retcode;
372	
373	    VM_DEBUG("thread %d (%s) exited\n", th->id, th->name);
374	
375	    // Disable pre-emption
376	    disable_interrupts();
377	
378	    acquire_spinlock(&thread_q_lock);
379	    list_add_tail(&dead_q, th);
380	    release_spinlock(&thread_q_lock);
381	    th->state = THREAD_DEAD;
382	    reschedule();
383	
384	    // Never will return...
385	
386	    panic("dead thread was rescheduled!");
387	}
388	
389	void make_thread_ready(struct thread *th)
390	{
391	    int old_flags;
392	
393	    assert(th->state != THREAD_READY);
394	    assert(th->state != THREAD_RUNNING);
395	    assert(th->state != THREAD_DEAD);
396	
397	    old_flags = acquire_spinlock_int(&thread_q_lock);
398	    th->state = THREAD_READY;
399	    list_add_tail(&ready_q, th);
400	    release_spinlock_int(&thread_q_lock, old_flags);
401	}
402	
403	void dump_process_list(void)
404	{
405	    int old_flags;
406	    struct process *proc;
407	    struct thread *th;
408	
409	    kprintf("process list\n");
410	    old_flags = acquire_spinlock_int(&process_list_lock);
411	    list_for_each(&process_list, proc, struct process)
412	    {
413	        kprintf("process %d\n", proc->id);
414	        acquire_spinlock(&proc->lock);
415	        multilist_for_each(&proc->thread_list, th, process_entry, struct thread)
416	            kprintf("  thread %d %p %s\n", th->id, th, th->name);
417	
418	        release_spinlock(&proc->lock);
419	    }
420	
421	    release_spinlock_int(&process_list_lock, old_flags);
422	}
